func (r *Report) summaryNodes() string {
	if r.Nodes.Error != "" {
		return truncate(r.Nodes.Error, 60)
	}
	n := len(r.Nodes.Data.Nodes)
	if n == 0 {
		return "no nodes"
	}
	unhealthy := 0
	for _, node := range r.Nodes.Data.Nodes {
		if node.UnhealthyReason != "" {
			unhealthy++
		}
	}
	if unhealthy == 0 {
		return fmt.Sprintf("%d nodes", n)
	}
	return fmt.Sprintf("%d nodes, %d unhealthy", n, unhealthy)
}

func (r *Report) summaryDeployments() string {
	if r.Deployments.Error != "" {
		return truncate(r.Deployments.Error, 60)
	}
	byNs := r.Deployments.Data.ByNamespace
	if len(byNs) == 0 {
		return "no deployments"
	}
	total, notReady := 0, 0
	for _, infos := range byNs {
		for _, d := range infos {
			total++
			if d.Replicas > 0 && d.Ready != d.Replicas {
				notReady++
			}
		}
	}
	if notReady == 0 {
		return fmt.Sprintf("%d deployments in %d namespaces", total, len(byNs))
	}
	return fmt.Sprintf("%d deployments in %d namespaces, %d not ready", total, len(byNs), notReady)
}

