func (r *Report) summaryOperator() string {
	if r.Operator.Error != "" {
		return truncate(r.Operator.Error, 60)
	}
	d := r.Operator.Data.Deployment
	if d == nil {
		return "no operator deployment"
	}
	depLine := fmt.Sprintf("%s %d/%d ready", d.Name, d.Ready, d.Replicas)
	deps := r.Operator.Data.DependentOperators
	if len(deps) == 0 {
		return depLine
	}
	notInstalled := 0
	for _, dep := range deps {
		if !dep.Installed {
			notInstalled++
		}
	}
	if notInstalled == 0 {
		return fmt.Sprintf("%s, %d dependents", depLine, len(deps))
	}
	return fmt.Sprintf("%s, %d dependents (%d not installed)", depLine, len(deps), notInstalled)
}

