func truncate(s string, maxLen int) string {
	s = strings.TrimSpace(s)
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen-3] + "..."
}

// formatTable renders rows as a simple aligned table with a header and separator.
func (r *Report) formatTable(rows []sectionRow) string {
	const (
		colSection = 12
		colStatus  = 6
	)
	pad := func(s string, n int) string {
		if len(s) >= n {
			return s
		}
		return s + strings.Repeat(" ", n-len(s))
	}
	var b strings.Builder
	b.WriteString(pad("SECTION", colSection))
	b.WriteString("  ")
	b.WriteString(pad("STATUS", colStatus))
	b.WriteString("  SUMMARY\n")
	b.WriteString(strings.Repeat("-", colSection))
	b.WriteString("  ")
	b.WriteString(strings.Repeat("-", colStatus))
	b.WriteString("  ")
	b.WriteString("-------\n")
	for _, row := range rows {
		b.WriteString(pad(row.Section, colSection))
		b.WriteString("  ")
		b.WriteString(pad(row.Status, colStatus))
		b.WriteString("  ")
		b.WriteString(row.Summary)
		b.WriteString("\n")
	}
	return b.String()
}

