func (r *Report) longDetailsQuotas() string {
	if r.Quotas.Error != "" {
		return "  " + r.Quotas.Error + "\n"
	}
	var b strings.Builder
	for ns, infos := range r.Quotas.Data.ByNamespace {
		for _, q := range infos {
			b.WriteString("  ")
			b.WriteString(ns)
			b.WriteString("/")
			b.WriteString(q.Name)
			if len(q.Exceeded) > 0 {
				b.WriteString(" exceeded: ")
				b.WriteString(strings.Join(q.Exceeded, ", "))
			}
			b.WriteString("\n")
		}
	}
	return b.String()
}

func (r *Report) longDetailsOperator() string {
	if r.Operator.Error != "" {
		return "  " + r.Operator.Error + "\n"
	}
	var b strings.Builder
	d := r.Operator.Data.Deployment
	if d != nil {
		b.WriteString("  ")
		b.WriteString(d.Name)
		b.WriteString(fmt.Sprintf(" %d/%d ready", d.Ready, d.Replicas))
		b.WriteString("\n")
	}
	for _, dep := range r.Operator.Data.DependentOperators {
		b.WriteString("  dependent: ")
		b.WriteString(dep.Name)
		switch {
		case !dep.Installed:
			b.WriteString(" not installed")
		case dep.Error != "":
			b.WriteString(" error: ")
			b.WriteString(dep.Error)
		case dep.Deployment != nil:
			b.WriteString(fmt.Sprintf(" %d/%d ready", dep.Deployment.Ready, dep.Deployment.Replicas))
		}
		b.WriteString("\n")
	}
	return b.String()
}

func (r *Report) longDetailsCRConditions(name string, conditions []ConditionSummary) string {
	if name == "" {
		return ""
	}
	var b strings.Builder
	for _, c := range conditions {
		b.WriteString("  ")
		b.WriteString(c.Type)
		b.WriteString(": ")
		b.WriteString(c.Status)
		if c.Message != "" {
			b.WriteString(" (")
			b.WriteString(truncate(c.Message, 50))
			b.WriteString(")")
		}
		b.WriteString("\n")
	}
	return b.String()
}
